diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..5b846f27cc78 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3081,6 +3081,13 @@ static Instruction *foldNestedSelects(SelectInst &OuterSelVal,
   } else // Not the pattern we were looking for.
     return nullptr;

+  // Fold select c2, (select c1, a, b), (select c1, b, a)
+  //      --> select (xor c1, c2), b, a
+  if (InnerSel.TrueVal == OuterSel.TrueVal &&
+      InnerSel.FalseVal == OuterSel.FalseVal)
+    return SelectInst::Create(Builder.CreateXor(InnerSel.Cond, AltCond),
+                              InnerSel.FalseVal, InnerSel.TrueVal);
+
   Value *SelInner = Builder.CreateSelect(
       AltCond, IsAndVariant ? OuterSel.TrueVal : InnerSel.FalseVal,
       IsAndVariant ? InnerSel.TrueVal : OuterSel.FalseVal);
@@ -3990,6 +3997,15 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *I = foldNestedSelects(SI, Builder))
     return I;

+  // Fold select c2, (select c1, a, b), (select c1, b, a)
+  //   --> select (xor c1, c2), b, a
+  Value *C1, *A, *B;
+  if (match(TrueVal, m_OneUse(m_Select(m_Value(C1), m_Value(A), m_Value(B)))) &&
+      match(FalseVal,
+            m_OneUse(m_Select(m_Specific(C1), m_Specific(B), m_Specific(A)))) &&
+      C1->getType() == CondVal->getType())
+    return SelectInst::Create(Builder.CreateXor(C1, CondVal), B, A);
+
   // Match logical variants of the pattern,
   // and transform them iff that gets rid of inversions.
   //   (~x) | y  -->  ~(x & (~y))

log.source_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %sel1 = select i1 %c1, i32 %a, i32 %b
  %sel2 = select i1 %c1, i32 %b, i32 %a
  %ret = select i1 %c2, i32 %sel1, i32 %sel2
  ret i32 %ret
}

